613	    case "debug/raw-event":
614	      return [convertDebugMessage(message)];
615	    case "command-execution":
616	      return convertCommandExecutionMessage(message);
617	    case "tool-call":
618	      return convertToolCallMessage(message);
619	    case "file-edit":
620	      return convertFileEditMessage(message);
621	    case "web-search":
622	      return convertWebSearchMessage(message);
623	    case "web-fetch":
