646	export function buildTimelineProjection({
647	  projection,
648	}: BuildTimelineProjectionArgs): TimelineProjection {
649	  const rows: TimelineSourceRow[] = [];
650	  const turns: TimelineProjectedTurn[] = [];
651	
652	  for (const entry of projection.entries) {
653	    switch (entry.kind) {
654	      case "message":
655	        rows.push(...convertViewMessage(entry.message));
656	        break;
657	      case "turn":
658	        turns.push(convertTurn(entry.turn));
659	        for (const message of entry.turn.messages ?? []) {
660	          rows.push(...convertViewMessage(message));
661	        }
662	        break;
663	      default:
664	        assertNever(entry);
665	    }
666	  }
667	
668	  return {
669	    rows,
670	    turns,
671	    state: {
672	      activeThinking: projection.state.activeThinking,
673	      pendingUserSteers:
674	        projection.state.pendingUserSteers.map(convertUserMessage),
675	    },
676	  };
677	}
