206	function getStepSummaryBuckets(
207	  rows: readonly TimelineWorkRow[],
208	): StepSummaryBucket[] {
209	  const buckets = new Map<TimelineSemanticKind, StepSummaryBucket>();
210	  rows.forEach((row, index) => {
211	    const semanticKind = getWorkSemanticKind(row);
212	    const existing = buckets.get(semanticKind);
213	    if (existing) {
214	      existing.rows.push(row);
215	      return;
216	    }
217	    buckets.set(semanticKind, {
218	      firstIndex: index,
219	      rows: [row],
220	      semanticKind,
221	    });
222	  });
223	  return [...buckets.values()].sort(
224	    (left, right) => left.firstIndex - right.firstIndex,
225	  );
226	}
