228	function formatExplorationSummary(rows: readonly TimelineWorkRow[]): string {
229	  const readPaths: string[] = [];
230	  let lists = 0;
231	  let searches = 0;
232	  for (const row of rows) {
233	    switch (row.workKind) {
234	      case "read":
235	        readPaths.push(row.path);
236	        break;
237	      case "list":
238	        lists += 1;
239	        break;
240	      case "search":
241	        searches += 1;
242	        break;
243	      case "command":
244	      case "delegation":
245	      case "file-change":
246	      case "tool":
247	      case "web-fetch":
248	      case "web-search":
249	        break;
250	      default:
251	        assertNever(row);
252	    }
253	  }
254	  const summary = joinText([
255	    uniqueCount(readPaths) > 0
256	      ? formatCount(uniqueCount(readPaths), "file", "files")
257	      : "",
258	    searches > 0 ? formatCount(searches, "search", "searches") : "",
259	    lists > 0 ? formatCount(lists, "list", "lists") : "",
260	  ]);
261	  return summary.length > 0 ? `explored ${summary}` : "";
262	}
