279	function formatFileChangeSummary(rows: readonly TimelineWorkRow[]): string {
280	  const fileRows = getFileChangeRows(rows);
281	  const verb = getFileChangeAggregateVerb(fileRows).toLowerCase();
282	  return `${verb} ${formatCount(
283	    countUniqueFileChangePaths(fileRows),
284	    "file",
285	    "files",
286	  )}`;
287	}
288	
289	function formatWebResearchSummary(rows: readonly TimelineWorkRow[]): string {
290	  let fetches = 0;
291	  let queries = 0;
292	  let emptySearches = 0;
293	  for (const row of rows) {
294	    if (row.workKind === "web-fetch") {
295	      fetches += 1;
296	    } else if (row.workKind === "web-search") {
297	      if (row.queries.length === 0) {
298	        emptySearches += 1;
299	      } else {
300	        queries += row.queries.length;
301	      }
302	    }
303	  }
304	  if (fetches > 0) {
305	    return `researched ${formatCount(
306	      fetches + queries + emptySearches,
307	      "item",
308	      "items",
309	    )}`;
310	  }
311	  if (queries > 0) {
312	    return `researched ${formatCount(queries, "query", "queries")}`;
313	  }
314	  return `searched the web ${formatCount(emptySearches, "time", "times")}`;
315	}
