774	function mergeAdjacentMarkupParts(
775	  parts: readonly TimelinePresentationTextPart[],
776	): TimelinePresentationMarkupPart[] {
777	  const mergedParts: TimelinePresentationMarkupPart[] = [];
778	  for (const part of parts) {
779	    const previous = mergedParts[mergedParts.length - 1];
780	    if (previous && previous.tone === part.tone) {
781	      previous.text += part.text;
782	      continue;
783	    }
784	    mergedParts.push({
785	      tone: part.tone,
786	      text: part.text,
787	    });
788	  }
789	  return mergedParts;
790	}
