803	  expandedRowIds,
804	  row,
805	}: FormatPresentationRowArgs): string[] {
806	  const indent = "  ".repeat(depth);
807	  const lines = [`${indent}${formatPlainLabel(row.label)}`];
808	  if (shouldExpandDetails(row, expandedRowIds)) {
809	    for (const detailLine of row.detailLines) {
810	      lines.push(`${indent}  ${detailLine}`);
811	    }
812	  }
813	  for (const child of row.children) {
814	    lines.push(
815	      ...formatPresentationRowAsPlainText({
816	        row: child,
817	        depth: depth + 1,
818	        expandedRowIds,
819	      }),
820	    );
821	  }
822	  return lines;
823	}
824	
825	function shouldExpandDetails(
826	  row: TimelinePresentationRow,
827	  expandedRowIds: TimelinePresentationDetailExpansion,
828	): boolean {
829	  if (expandedRowIds === "all") {
830	    return row.detailLines.length > 0;
831	  }
832	  return expandedRowIds.has(row.id);
833	}
834	
835	function formatPresentationRowAsMarkup({
836	  depth,
837	  expandedRowIds,
838	  row,
839	}: FormatPresentationRowArgs): string[] {
840	  const indent = "  ".repeat(depth);
841	  const lines = [`${indent}${formatMarkupLabel(row.label)}`];
842	  if (shouldExpandDetails(row, expandedRowIds)) {
843	    for (const detailLine of row.detailLines) {
844	      lines.push(`${indent}  | ${escapeMarkupText(detailLine)}`);
845	    }
846	  }
847	  for (const child of row.children) {
848	    lines.push(
849	      ...formatPresentationRowAsMarkup({
850	        row: child,
851	        depth: depth + 1,
852	        expandedRowIds,
853	      }),
854	    );
855	  }
856	  return lines;
857	}
858	
859	export function formatTimelinePresentationAsPlainText({
860	  expandedRowIds = new Set(),
861	  rows,
862	}: FormatPresentationRowsArgs): string {
863	  return rows
864	    .flatMap((row) =>
865	      formatPresentationRowAsPlainText({ row, depth: 0, expandedRowIds }),
866	    )
867	    .join("\n");
868	}
869	
870	export function formatTimelinePresentationAsMarkup({
871	  expandedRowIds = new Set(),
872	  rows,
873	}: FormatPresentationRowsArgs): string {
874	  return rows
875	    .flatMap((row) =>
876	      formatPresentationRowAsMarkup({ row, depth: 0, expandedRowIds }),
877	    )
878	    .join("\n");
879	}
