{"jsonrpc":"2.0","method":"sdk/message","params":{"threadId":"thr_2mp6rkmsxy","message":{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_0155LmoANgifFG1A8fuLJYWb","type":"tool_result","content":"1	import type { ViewFileEditChange, ViewFileEditMessage } from "@bb/domain";
2	
3	type FileEditChange = ViewFileEditChange;
4	
5	export type FileChangeAction = "created" | "deleted" | "renamed" | "edited";
6	export type FileChangeSummaryAction = FileChangeAction | "changed";
7	export interface FileChangeDiffStats {
8	  added: number;
9	  removed: number;
10	}
11	
12	export interface FileChangeGroup {
13	  changes: ViewFileEditChange[];
14	  identity: string;
15	  stats: FileChangeDiffStats;
16	}
17	
18	interface FormatFileChangeActionLabelArgs {
19	  action: FileChangeSummaryAction;
20	  tense: "past" | "present";
21	}
22	
23	interface FormatFileChangeDetailLineArgs {
24	  change: FileEditChange;
25	  status: ViewFileEditMessage["status"];
26	}
27	
28	interface FormatFileChangeGroupDetailLabelArgs {
29	  group: FileChangeGroup;
30	  status: ViewFileEditMessage["status"];
31	}
32	
33	const EMPTY_DIFF_STATS: FileChangeDiffStats = {
34	  added: 0,
35	  removed: 0,
36	};
37	
38	export function fileNameFromPath(path: string): string {
39	  const normalizedPath = path.replaceAll("\\", "/");
40	  const segments = normalizedPath.split("/");
41	  const candidate = segments[segments.length - 1];
42	  return candidate && candidate.length > 0 ? candidate : path;
43	}
44	
45	export function fileChangeIdentity(change: FileEditChange): string {
46	  return (change.movePath ?? change.path).replaceAll("\\", "/");
47	}
48	
49	export function formatFileChangeName(change: FileEditChange): string {
50	  const sourceName = fileNameFromPath(change.path);
51	  if (!change.movePath) {
52	    return sourceName;
53	  }
54	  const destinationName = fileNameFromPath(change.movePath);
55	  return `${sourceName} → ${destinationName}`;
56	}
57	
58	function normalizeToken(value: string | undefined): string {
59	  if (!value) return "";
60	  return value.toLowerCase().replaceAll(/[^a-z0-9]/g, "");
61	}
62	
63	function hasSubstantiveDiff(change: FileEditChange): boolean {
64	  const diff = change.diff;
65	  if (!diff) return false;
66	  for (const line of diff.split("\n")) {
67	    if (line.startsWith("+++ ") || line.startsWith("--- ")) continue;
68	    if (line.startsWith("+") || line.startsWith("-")) return true;
69	  }
70	  return false;
71	}
72	
73	export function getFileChangeAction(change: FileEditChange): FileChangeAction {
74	  if (change.movePath) {
75	    return hasSubstantiveDiff(change) ? "edited" : "renamed";
76	  }
77	
78	  const token = normalizeToken(change.kind);
79	  if (token.includes("add") || token.includes("create")) return "created";
80	  if (token.includes("delete") || token.includes("remove")) return "deleted";
81	  return "edited";
82	}
83	
84	export function summarizeFileChangeAction(
85	  changes: readonly FileEditChange[],
86	): FileChangeSummaryAction {
87	  const firstChange = changes[0];
88	  if (!firstChange) return "edited";
89	
90	  const firstAction = getFileChangeAction(firstChange);
91	  return changes.some((change) => getFileChangeAction(change) !== firstAction)
92	    ? "changed"
93	    : firstAction;
94	}
95	
96	export function formatFileChangeActionLabel({
97	  action,
98	  tense,
99	}: FormatFileChangeActionLabelArgs): string {
100	  switch (action) {
101	    case "changed":
102	      return tense === "present" ? "Changing" : "Changed";
103	    case "created":
104	      return tense === "present" ? "Creating" : "Created";
105	    case "deleted":
106	      return tense === "present" ? "Deleting" : "Deleted";
107	    case "edited":
108	      return tense === "present" ? "Editing" : "Edited";
109	    case "renamed":
110	      return tense === "present" ? "Renaming" : "Renamed";
111	  }
112	}
113	
114	export function formatFileChangeActionInfinitive(
115	  action: FileChangeSummaryAction,
116	): string {
117	  switch (action) {
118	    case "changed":
119	      return "edit";
120	    case "created":
121	      return "create";
122	    case "deleted":
123	      return "delete";
124	    case "edited":
125	      return "edit";
126	    case "renamed":
127	      return "rename";
128	  }
129	}
130	
131	export function formatFileChangeDisplayName(change: FileEditChange): string {
132	  if (change.movePath && getFileChangeAction(change) === "edited") {
133	    return fileNameFromPath(change.movePath);
134	  }
135	  return formatFileChangeName(change);
136	}
137	
138	export function countUniqueChangedFiles(
139	  changes: readonly FileEditChange[],
140	): number {
141	  const seenFiles = new Set<string>();
142	  for (const change of changes) {
143	    seenFiles.add(fileChangeIdentity(change));
144	  }
145	  return seenFiles.size;
146	}
147	
148	export function summarizeFileChangeDiffStats(
149	  changes: readonly FileEditChange[],
150	): FileChangeDiffStats {
151	  return changes.reduce(
152	    (totals, change) => {
153	      const stats = getFileChangeDiffStats(change);
154	      return {
155	        added: totals.added + stats.added,
156	        removed: totals.removed + stats.removed,
157	      };
158	    },
159	    EMPTY_DIFF_STATS,
160	  );
161	}
162	
163	export function groupFileChanges(
164	  changes: readonly ViewFileEditChange[],
165	): FileChangeGroup[] {
166	  const groupsByIdentity = new Map<string, ViewFileEditChange[]>();
167	  const orderedIdentities: string[] = [];
168	
169	  for (const change of changes) {
170	    const identity = fileChangeIdentity(change);
171	    const existing = groupsByIdentity.get(identity);
172	    if (existing) {
173	      existing.push(change);
174	      continue;
175	    }
176	    groupsByIdentity.set(identity, [change]);
177	    orderedIdentities.push(identity);
178	  }
179	
180	  return orderedIdentities.map((identity) => {
181	    const groupChanges = groupsByIdentity.get(identity) ?? [];
182	    return {
183	      changes: groupChanges,
184	      identity,
185	      stats: groupChanges.reduce(
186	        (totals, change) => {
187	          const stats = getFileChangeDiffStats(change);
188	          return {
189	            added: totals.added + stats.added,
190	            removed: totals.removed + stats.removed,
191	          };
192	        },
193	        EMPTY_DIFF_STATS,
194	      ),
195	    };
196	  });
197	}
198	
199	export function getFileChangeDiffStats(
200	  change: FileEditChange,
201	): FileChangeDiffStats {
202	  const diff = change.diff;
203	  if (!diff) return EMPTY_DIFF_STATS;
204	  let added = 0;
205	  let removed = 0;
206	  let sawUnifiedDiffLine = false;
207	  for (const line of diff.split("\n")) {
208	    if (line.startsWith("+++ ") || line.startsWith("--- ")) continue;
209	    if (line.startsWith("+")) {
210	      sawUnifiedDiffLine = true;
211	      added += 1;
212	      continue;
213	    }
214	    if (line.startsWith("-")) {
215	      sawUnifiedDiffLine = true;
216	      removed += 1;
217	    }
218	  }
219	  if (sawUnifiedDiffLine) {
220	    return { added, removed };
221	  }
222	  const action = getFileChangeAction(change);
223	  if (action === "created" || action === "deleted") {
224	    const plainContentLines = diff
225	      .split("\n")
226	      .map((line) => line.trimEnd())
227	      .filter((line) => line.trim().length > 0)
228	      .filter((line) => {
229	        return !(
230	          line.startsWith("diff --git") ||
231	          line.startsWith("index ") ||
232	          line.startsWith("new file mode ") ||
233	          line.startsWith("deleted file mode ") ||
234	          line.startsWith("similarity index ") ||
235	          line.startsWith("rename from ") ||
236	          line.startsWith("rename to ")
237	        );
238	      }).length;
239	    if (action === "created") return { added: plainContentLines, removed: 0 };
240	    return { added: 0, removed: plainContentLines };
241	  }
242	  return { added, removed };
243	}
244	
245	export function hasFileChangeDiffStats(stats: FileChangeDiffStats): boolean {
246	  return stats.added > 0 || stats.removed > 0;
247	}
248	
249	export function formatFileChangeDiffStatsSuffix(
250	  stats: FileChangeDiffStats,
251	): string {
252	  return hasFileChangeDiffStats(stats)
253	    ? ` +${stats.added} -${stats.removed}`
254	    : "";
255	}
256	
257	export function formatFileChangeDetailLabel({
258	  change,
259	  status,
260	}: FormatFileChangeDetailLineArgs): string {
261	  const action = getFileChangeAction(change);
262	  const actionLabel = formatFileChangeActionLabel({
263	    action,
264	    tense: status === "pending" ? "present" : "past",
265	  });
266	  return `${actionLabel} ${formatFileChangeDisplayName(change)}`;
267	}
268	
269	export function formatFileChangeGroupDetailLabel({
270	  group,
271	  status,
272	}: FormatFileChangeGroupDetailLabelArgs): string {
273	  const displayChange =
274	    group.changes[group.changes.length - 1] ?? group.changes[0];
275	  if (!displayChange) {
276	    return "Edited file";
277	  }
278	  const actionLabel = formatFileChangeActionLabel({
279	    action: summarizeFileChangeAction(group.changes),
280	    tense: status === "pending" ? "present" : "past",
281	  });
282	  return `${actionLabel} ${formatFileChangeDisplayName(displayChange)}`;
283	}
284	
285	export function formatFileChangeDetailLine(
286	  args: FormatFileChangeDetailLineArgs,
287	): string {
288	  const statsSuffix = formatFileChangeDiffStatsSuffix(
289	    getFileChangeDiffStats(args.change),
290	  );
291	  return `${formatFileChangeDetailLabel(args)}${statsSuffix}`;
292	}
293	"}]},"parent_tool_use_id":"toolu_01CSZSHz5QYNrt6w9tm9e3jz","session_id":"e8bf7a84-63be-4471-bc25-5d1dc16391ca","uuid":"df6f6caf-bf6f-47ad-a3c3-a77315d8602b","timestamp":"2026-04-30T21:57:55.464Z"}}}

