143	    seenFiles.add(fileChangeIdentity(change));
144	  }
145	  return seenFiles.size;
146	}
147	
148	export function summarizeFileChangeDiffStats(
149	  changes: readonly FileEditChange[],
150	): FileChangeDiffStats {
151	  return changes.reduce(
152	    (totals, change) => {
153	      const stats = getFileChangeDiffStats(change);
154	      return {
155	        added: totals.added + stats.added,
156	        removed: totals.removed + stats.removed,
157	      };
158	    },
159	    EMPTY_DIFF_STATS,
160	  );
161	}
162	
163	export function groupFileChanges(
164	  changes: readonly ViewFileEditChange[],
165	): FileChangeGroup[] {
166	  const groupsByIdentity = new Map<string, ViewFileEditChange[]>();
167	  const orderedIdentities: string[] = [];
168	
169	  for (const change of changes) {
170	    const identity = fileChangeIdentity(change);
171	    const existing = groupsByIdentity.get(identity);
172	    if (existing) {
173	      existing.push(change);
174	      continue;
175	    }
176	    groupsByIdentity.set(identity, [change]);
177	    orderedIdentities.push(identity);
178	  }
179	
180	  return orderedIdentities.map((identity) => {
181	    const groupChanges = groupsByIdentity.get(identity) ?? [];
182	    return {
183	      changes: groupChanges,
184	      identity,
185	      stats: groupChanges.reduce(
186	        (totals, change) => {
187	          const stats = getFileChangeDiffStats(change);
188	          return {
189	            added: totals.added + stats.added,
190	            removed: totals.removed + stats.removed,
191	          };
192	        },
193	        EMPTY_DIFF_STATS,
194	      ),
195	    };
196	  });
197	}
198	
199	export function getFileChangeDiffStats(
200	  change: FileEditChange,
201	): FileChangeDiffStats {
202	  const diff = change.diff;
203	  if (!diff) return EMPTY_DIFF_STATS;
204	  let added = 0;
205	  let removed = 0;
206	  let sawUnifiedDiffLine = false;
207	  for (const line of diff.split("\n")) {
208	    if (line.startsWith("+++ ") || line.startsWith("--- ")) continue;
209	    if (line.startsWith("+")) {
210	      sawUnifiedDiffLine = true;
211	      added += 1;
212	      continue;
213	    }
214	    if (line.startsWith("-")) {
215	      sawUnifiedDiffLine = true;
216	      removed += 1;
217	    }
218	  }
219	  if (sawUnifiedDiffLine) {
220	    return { added, removed };
221	  }
222	  const action = getFileChangeAction(change);
223	  if (action === "created" || action === "deleted") {
224	    const plainContentLines = diff
225	      .split("\n")
226	      .map((line) => line.trimEnd())
227	      .filter((line) => line.trim().length > 0)
228	      .filter((line) => {
229	        return !(
230	          line.startsWith("diff --git") ||
231	          line.startsWith("index ") ||
232	          line.startsWith("new file mode ") ||
233	          line.startsWith("deleted file mode ") ||
234	          line.startsWith("similarity index ") ||
235	          line.startsWith("rename from ") ||
236	          line.startsWith("rename to ")
237	        );
238	      }).length;
239	    if (action === "created") return { added: plainContentLines, removed: 0 };
240	    return { added: 0, removed: plainContentLines };
241	  }
242	  return { added, removed };
243	}
244	
245	export function hasFileChangeDiffStats(stats: FileChangeDiffStats): boolean {
246	  return stats.added > 0 || stats.removed > 0;
247	}
248	
249	export function formatFileChangeDiffStatsSuffix(
250	  stats: FileChangeDiffStats,
251	): string {
252	  return hasFileChangeDiffStats(stats)
253	    ? ` +${stats.added} -${stats.removed}`
254	    : "";
255	}
256	
257	export function formatFileChangeDetailLabel({
258	  change,
259	  status,
260	}: FormatFileChangeDetailLineArgs): string {
261	  const action = getFileChangeAction(change);
262	  const actionLabel = formatFileChangeActionLabel({
263	    action,
264	    tense: status === "pending" ? "present" : "past",
265	  });
266	  return `${actionLabel} ${formatFileChangeDisplayName(change)}`;
267	}
268	
269	export function formatFileChangeGroupDetailLabel({
270	  group,
271	  status,
272	}: FormatFileChangeGroupDetailLabelArgs): string {
273	  const displayChange =
274	    group.changes[group.changes.length - 1] ?? group.changes[0];
275	  if (!displayChange) {
276	    return "Edited file";
277	  }
278	  const actionLabel = formatFileChangeActionLabel({
279	    action: summarizeFileChangeAction(group.changes),
280	    tense: status === "pending" ? "present" : "past",
281	  });
282	  return `${actionLabel} ${formatFileChangeDisplayName(displayChange)}`;
283	}
284	
285	export function formatFileChangeDetailLine(
286	  args: FormatFileChangeDetailLineArgs,
287	): string {
288	  const statsSuffix = formatFileChangeDiffStatsSuffix(
289	    getFileChangeDiffStats(args.change),
290	  );
291	  return `${formatFileChangeDetailLabel(args)}${statsSuffix}`;
292	}
