133	function compactSummaryThreadEvents(
134	  events: ThreadEventWithMeta[],
135	): ThreadEventWithMeta[] {
136	  let agentMessageDeltaCount = 0;
137	  const completedAssistantKeys = new Set<string>();
138	  for (const eventWithMeta of events) {
139	    const { event } = eventWithMeta;
140	    if (event.type === "item/agentMessage/delta") {
141	      agentMessageDeltaCount += 1;
142	      continue;
143	    }
144	    if (event.type === "item/completed" && event.item.type === "agentMessage") {
145	      const identity = resolveBufferedTextIdentity({
146	        decoded: event,
147	        kind: "assistant",
148	      });
149	      if (identity) {
150	        completedAssistantKeys.add(createBufferedTextInstanceKey(identity));
151	      }
152	    }
153	  }
154	
155	  if (
156	    agentMessageDeltaCount < MIN_AGENT_MESSAGE_DELTAS_FOR_SUMMARY_COMPACTION ||
157	    completedAssistantKeys.size === 0
158	  ) {
159	    return events;
160	  }
161	
162	  const retainedCompletedDeltaKeys = new Set<string>();
163	  const compactedEvents: ThreadEventWithMeta[] = [];
164	
165	  for (const eventWithMeta of events) {
166	    const { event } = eventWithMeta;
167	    if (event.type !== "item/agentMessage/delta") {
168	      compactedEvents.push(eventWithMeta);
169	      continue;
170	    }
171	
172	    const identity = resolveBufferedTextIdentity({
173	      decoded: event,
174	      kind: "assistant",
175	    });
176	    if (!identity) {
