178	      continue;
179	    }
180	
181	    const assistantKey = createBufferedTextInstanceKey(identity);
182	    if (!completedAssistantKeys.has(assistantKey)) {
183	      compactedEvents.push(eventWithMeta);
184	      continue;
185	    }
186	    if (retainedCompletedDeltaKeys.has(assistantKey)) {
187	      continue;
188	    }
189	    retainedCompletedDeltaKeys.add(assistantKey);
190	    compactedEvents.push(eventWithMeta);
191	  }
192	
193	  return compactedEvents;
