683	export function listThreadTurnInterruptionEventStates(
684	  db: ThreadEventQueryDb,
685	  args: ListThreadTurnInterruptionEventStatesArgs,
686	): ThreadTurnInterruptionEventState[] {
687	  const threadIds = [...new Set(args.threadIds)];
688	  if (threadIds.length === 0) {
689	    return [];
690	  }
691	
692	  const statesByThreadId = new Map<string, ThreadTurnInterruptionEventState>(
693	    threadIds.map((threadId) => [
694	      threadId,
695	      {
696	        activeTurnId: null,
697	        latestProviderThreadId: null,
698	        threadId,
699	      },
700	    ]),
701	  );
702	
703	  const latestStartedTurnRows = db
704	    .select({
705	      threadId: events.threadId,
706	      turnId: events.turnId,
707	    })
708	    .from(events)
709	    .where(
710	      and(
711	        inArray(events.threadId, threadIds),
712	        eq(events.type, "turn/started"),
713	        isNotNull(events.turnId),
714	        sql`${events.sequence} = (
715	          SELECT MAX(latest.sequence)
716	          FROM events AS latest
717	          WHERE latest.thread_id = ${events.threadId}
718	            AND latest.type = 'turn/started'
719	            AND latest.turn_id IS NOT NULL
720	        )`,
721	        sql`NOT EXISTS (
722	          SELECT 1
723	          FROM events AS completed
724	          WHERE completed.thread_id = ${events.threadId}
725	            AND completed.turn_id = ${events.turnId}
726	            AND completed.type = 'turn/completed'
727	        )`,
728	      ),
729	    )
730	    .all();
731	  for (const row of latestStartedTurnRows) {
732	    if (row.turnId === null) {
733	      continue;
734	    }
735	    const state = statesByThreadId.get(row.threadId);
736	    if (state) {
737	      state.activeTurnId = row.turnId;
738	    }
739	  }
740	
741	  const latestProviderRows = db
742	    .select({
743	      providerThreadId: events.providerThreadId,
744	      threadId: events.threadId,
745	    })
746	    .from(events)
747	    .where(
748	      and(
749	        inArray(events.threadId, threadIds),
750	        isNotNull(events.providerThreadId),
751	        sql`${events.sequence} = (
752	          SELECT MAX(latest.sequence)
753	          FROM events AS latest
754	          WHERE latest.thread_id = ${events.threadId}
755	            AND latest.provider_thread_id IS NOT NULL
756	        )`,
757	      ),
758	    )
759	    .all();
760	  for (const row of latestProviderRows) {
761	    if (row.providerThreadId === null) {
762	      continue;
763	    }
764	    const state = statesByThreadId.get(row.threadId);
765	    if (state) {
766	      state.latestProviderThreadId = row.providerThreadId;
767	    }
768	  }
769	
770	  return threadIds.flatMap((threadId) => {
771	    const state = statesByThreadId.get(threadId);
772	    return state ? [state] : [];
773	  });
774	}
