888	function pruneLatestRowsForContextWindowUsageBeforeSequence(
889	  db: DbConnection,
890	  args: {
891	    contextWindowJsonPath: string;
892	    eventType:
893	      | "thread/contextWindowUsage/updated"
894	      | "thread/tokenUsage/updated";
895	    sequenceCutoff: number;
896	    threadId: string;
897	  },
898	): number {
899	  if (args.sequenceCutoff <= 0) {
900	    return 0;
901	  }
902	
903	  // The timeline needs the latest totals row plus the latest older row that
904	  // still carries a non-null modelContextWindow.
905	  const result = db.run(
906	    sql`DELETE FROM events
907	        WHERE ${events.threadId} = ${args.threadId}
908	          AND ${events.type} = ${args.eventType}
909	          AND ${events.sequence} <= ${args.sequenceCutoff}
910	          AND ${events.id} NOT IN (
911	            SELECT latest.id
912	            FROM events latest
913	            WHERE latest.thread_id = ${args.threadId}
914	              AND latest.type = ${args.eventType}
915	            ORDER BY latest.sequence DESC
916	            LIMIT 1
917	          )
918	          AND ${events.id} NOT IN (
919	            SELECT latest_context.id
920	            FROM events latest_context
921	            WHERE latest_context.thread_id = ${args.threadId}
922	              AND latest_context.type = ${args.eventType}
923	              AND json_extract(latest_context.data, ${args.contextWindowJsonPath}) IS NOT NULL
924	            ORDER BY latest_context.sequence DESC
925	            LIMIT 1
