87	/**
88	 * Insert events with dedup on (threadId, sequence).
89	 * Uses INSERT OR IGNORE to skip duplicates.
90	 * Returns the count and input indexes of actually inserted events.
91	 */
92	export function insertEvents(
93	  db: DbConnection,
94	  notifier: DbNotifier,
95	  eventInputs: InsertEventInput[],
96	): InsertEventsResult {
97	  if (eventInputs.length === 0) {
98	    return {
99	      insertedCount: 0,
100	      insertedInputIndexes: [],
101	    };
102	  }
103	
104	  let insertedCount = 0;
105	  const insertedInputIndexes: number[] = [];
106	
107	  // Track which threads get new events for notification
108	  const threadIds = new Set<string>();
109	
110	  for (const [index, input] of eventInputs.entries()) {
111	    const id = createEventId();
112	    const createdAt = input.createdAt ?? Date.now();
113	    const turnId = getThreadEventScopeTurnId(input.scope) ?? null;
114	    const result = db.run(
115	      sql`INSERT OR IGNORE INTO events (id, thread_id, environment_id, scope_kind, turn_id, provider_thread_id, sequence, type, item_id, item_kind, data, created_at)
116	          VALUES (${id}, ${input.threadId}, ${input.environmentId ?? null}, ${input.scope.kind}, ${turnId}, ${input.providerThreadId ?? null}, ${input.sequence}, ${input.type}, ${input.itemId}, ${input.itemKind}, ${input.data}, ${createdAt})`,
117	    );
118	    if (result.changes > 0) {
119	      insertedCount++;
120	      insertedInputIndexes.push(index);
121	      threadIds.add(input.threadId);
122	    }
123	  }
124	
125	  for (const threadId of threadIds) {
126	    notifier.notifyThread(threadId, ["events-appended"]);
127	  }
128	
129	  return {
130	    insertedCount,
131	    insertedInputIndexes,
132	  };
133	}
