149	export function appendStoredThreadEventsInTransaction(
150	  db: DbTransaction,
151	  eventArgs: readonly AppendStoredThreadEventArgs[],
152	): number[] {
153	  if (eventArgs.length === 0) {
154	    return [];
155	  }
156	
157	  const now = Date.now();
158	  const threadIds = [...new Set(eventArgs.map((args) => args.threadId))];
159	  const highWaterMarks = getHighWaterMarks(db, threadIds);
160	  const nextSequencesByThreadId = new Map(
161	    threadIds.map((threadId) => [
162	      threadId,
163	      (highWaterMarks[threadId] ?? 0) + 1,
164	    ]),
165	  );
166	
167	  const sequences: number[] = [];
168	  for (const args of eventArgs) {
169	    const sequence = nextSequencesByThreadId.get(args.threadId);
170	    if (sequence === undefined) {
171	      throw new Error(`Missing event sequence for thread: ${args.threadId}`);
172	    }
173	
174	    const itemFields = deriveStoredEventItemFieldsFromSource({
175	      type: args.type,
176	      item: "item" in args.data ? args.data.item : undefined,
177	      itemId: "itemId" in args.data ? args.data.itemId : undefined,
178	    });
179	    const turnId = getThreadEventScopeTurnId(args.scope) ?? null;
180	
181	    db.run(
182	      sql`INSERT INTO events
183	        (id, thread_id, environment_id, scope_kind, turn_id, provider_thread_id, sequence, type, item_id, item_kind, data, created_at)
184	        VALUES (
185	          ${createEventId()},
186	          ${args.threadId},
187	          ${args.environmentId ?? null},
188	          ${args.scope.kind},
189	          ${turnId},
190	          ${args.providerThreadId ?? null},
191	          ${sequence},
192	          ${args.type},
193	          ${itemFields.itemId},
194	          ${itemFields.itemKind},
195	          ${JSON.stringify(args.data)},
196	          ${now}
197	        )`,
198	    );
199	
200	    sequences.push(sequence);
201	    nextSequencesByThreadId.set(args.threadId, sequence + 1);
202	  }
203	
204	  return sequences;
205	}
