38	export function fileNameFromPath(path: string): string {
39	  const normalizedPath = path.replaceAll("\\", "/");
40	  const segments = normalizedPath.split("/");
41	  const candidate = segments[segments.length - 1];
42	  return candidate && candidate.length > 0 ? candidate : path;
43	}
44	
45	export function fileChangeIdentity(change: FileEditChange): string {
46	  return (change.movePath ?? change.path).replaceAll("\\", "/");
47	}
48	
49	export function formatFileChangeName(change: FileEditChange): string {
50	  const sourceName = fileNameFromPath(change.path);
51	  if (!change.movePath) {
52	    return sourceName;
53	  }
54	  const destinationName = fileNameFromPath(change.movePath);
55	  return `${sourceName} → ${destinationName}`;
56	}
57	
58	function normalizeToken(value: string | undefined): string {
59	  if (!value) return "";
60	  return value.toLowerCase().replaceAll(/[^a-z0-9]/g, "");
61	}
62	
63	function hasSubstantiveDiff(change: FileEditChange): boolean {
64	  const diff = change.diff;
65	  if (!diff) return false;
66	  for (const line of diff.split("\n")) {
67	    if (line.startsWith("+++ ") || line.startsWith("--- ")) continue;
68	    if (line.startsWith("+") || line.startsWith("-")) return true;
69	  }
70	  return false;
71	}
