607	function buildTimelineRowBehaviorMap({
608	  enclosingScopeInProgress,
609	  getTurnRows,
610	  rows,
611	}: BuildTimelineRowBehaviorMapArgs): ReadonlyMap<string, TimelineRowBehavior> {
612	  const behaviorById = new Map<string, TimelineRowBehavior>();
613	
614	  const visitTimelineRows = (
615	    timelineRows: readonly TimelineRow[],
616	    scopeInProgress: boolean,
617	  ) => {
618	    timelineRows.forEach((row, index) => {
619	      visitTimelineRow({
620	        row,
621	        isTail: index === timelineRows.length - 1,
622	        scopeInProgress,
623	      });
624	    });
625	  };
