572	function buildTimelineRowBehavior({
573	  enclosingScopeInProgress,
574	  isTail,
575	  row,
576	}: BuildTimelineRowBehaviorArgs): TimelineRowBehavior {
577	  switch (row.kind) {
578	    case "conversation":
579	    case "system":
580	    case "turn":
581	      return {
582	        autoExpand: false,
583	        isOngoing: false,
584	      };
585	    case "group": {
586	      const isOngoing =
587	        row.groupKind === "semantic-bundle" &&
588	        isTail &&
589	        enclosingScopeInProgress;
590	      return {
591	        autoExpand: isOngoing,
592	        isOngoing,
593	      };
594	    }
595	    case "work": {
596	      const isOngoing = row.status === "pending";
597	      return {
598	        autoExpand: isOngoing,
599	        isOngoing,
600	      };
601	    }
602	    default:
603	      return assertNever(row);
604	  }
605	}
