607	function buildTimelineRowBehaviorMap({
608	  enclosingScopeInProgress,
609	  getTurnRows,
610	  rows,
611	}: BuildTimelineRowBehaviorMapArgs): ReadonlyMap<string, TimelineRowBehavior> {
612	  const behaviorById = new Map<string, TimelineRowBehavior>();
613	
614	  const visitTimelineRows = (
615	    timelineRows: readonly TimelineRow[],
616	    scopeInProgress: boolean,
617	  ) => {
618	    timelineRows.forEach((row, index) => {
619	      visitTimelineRow({
620	        row,
621	        isTail: index === timelineRows.length - 1,
622	        scopeInProgress,
623	      });
624	    });
625	  };
626	
627	  const visitTimelineRow = ({
628	    isTail,
629	    row,
630	    scopeInProgress,
631	  }: VisitTimelineRowArgs) => {
632	    const behavior = buildTimelineRowBehavior({
633	      enclosingScopeInProgress: scopeInProgress,
634	      isTail,
635	      row,
636	    });
637	    behaviorById.set(row.id, behavior);
638	
639	    if (row.kind === "group") {
640	      visitTimelineRows(row.children, behavior.isOngoing);
641	      return;
642	    }
643	
644	    if (row.kind === "turn") {
645	      const childRows = getTurnRows(row);
646	      if (childRows) {
647	        visitTimelineRows(childRows, false);
648	      }
649	      return;
650	    }
651	
652	    if (row.kind === "work" && row.workKind === "delegation") {
653	      visitTimelineRows(row.childRows, behavior.isOngoing);
654	    }
655	  };
656	
657	  visitTimelineRows(rows, enclosingScopeInProgress);
658	  return behaviorById;
659	}
