411	function isScrolledNearBottom(
412	  element: Pick<HTMLElement, "scrollHeight" | "clientHeight" | "scrollTop">,
413	): boolean {
414	  const maxScrollOffset = element.scrollHeight - element.clientHeight;
415	  if (maxScrollOffset <= DEFAULT_SCROLL_STICK_THRESHOLD_PX) {
416	    return true;
417	  }
418	  const distanceFromBottom = maxScrollOffset - element.scrollTop;
419	  return distanceFromBottom <= DEFAULT_SCROLL_STICK_THRESHOLD_PX;
420	}
