422	/**
423	 * Returns whether `ref`'s element has content that exceeds its visible height.
424	 * Uses ResizeObserver to re-measure on width changes; additional content-level
425	 * dependencies can be passed via `deps` to re-run the check when the contents
426	 * change without triggering a size change (e.g. when the element is clamped).
427	 * When `enabled` is false the observer is skipped and the result stays `false`.
428	 */
429	export function useIsOverflowing(
430	  ref: RefObject<HTMLElement | null>,
431	  enabled: boolean,
432	  deps: readonly unknown[] = [],
433	): boolean {
434	  const [isOverflowing, setIsOverflowing] = useState(false);
435	
436	  useLayoutEffect(() => {
437	    if (!enabled) {
438	      setIsOverflowing(false);
439	      return;
440	    }
441	    const el = ref.current;
442	    if (!el) return;
443	    const check = () => {
444	      setIsOverflowing(el.scrollHeight > el.clientHeight + 1);
445	    };
446	    check();
447	    const observer = new ResizeObserver(check);
448	    observer.observe(el);
449	    return () => observer.disconnect();
450	    // eslint-disable-next-line react-hooks/exhaustive-deps
451	  }, [enabled, ref, ...deps]);
452	
453	  return isOverflowing;
454	}
455	
456	export function useStickyBottomAutoScroll<ElementType extends HTMLElement>({
457	  isExpanded,
458	  scrollDep,
459	}: StickyBottomAutoScrollArgs) {
460	  const elementRef = useRef<ElementType | null>(null);
461	  const shouldStickToBottomRef = useRef(true);
462	
463	  useEffect(() => {
464	    if (!isExpanded) return;
465	    shouldStickToBottomRef.current = true;
466	  }, [isExpanded]);
467	
468	  useEffect(() => {
469	    if (!isExpanded || !shouldStickToBottomRef.current) return;
470	    const element = elementRef.current;
471	    if (!element) return;
472	    element.scrollTo({
473	      top: element.scrollHeight,
474	      behavior: getScrollAnimationBehavior(),
475	    });
476	  }, [isExpanded, scrollDep]);
477	
478	  const handleScroll = () => {
479	    const element = elementRef.current;
480	    if (!element) return;
481	    shouldStickToBottomRef.current = isScrolledNearBottom(element);
482	  };
483	
484	  return { elementRef, handleScroll };
485	}
