159	    return events;
160	  }
161	
162	  const retainedCompletedDeltaKeys = new Set<string>();
163	  const compactedEvents: ThreadEventWithMeta[] = [];
164	
165	  for (const eventWithMeta of events) {
166	    const { event } = eventWithMeta;
167	    if (event.type !== "item/agentMessage/delta") {
168	      compactedEvents.push(eventWithMeta);
169	      continue;
170	    }
171	
