229	export function buildThreadTimeline(
230	  db: DbConnection,
231	  thread: Thread,
232	  options: BuildThreadTimelineOptions,
233	): ThreadTimelineResponse {
234	  const includeNestedRows = options.includeNestedRows ?? false;
235	  const includeProviderUnhandledOperations =
