63	    message.isManagerUserMessage === true
64	  ) {
65	    return true;
66	  }
67	  return false;
68	}
69	
70	function buildManagerConversationRows(projection: ViewProjection): TimelineRow[] {
71	  const visibleMessages = flattenProjectionMessagesDeep(projection).filter(
72	    isManagerConversationMessage,
73	  );
74	  return buildTimelineProjection({
75	    projection: {
76	      entries: visibleMessages.map((message) => ({
77	        kind: "message",
78	        message,
79	      })),
80	      state: {
81	        activeThinking: null,
82	        pendingUserSteers: [],
83	        tasks: [],
84	      },
85	    },
86	  }).rows;
87	}
88	
89	function getEventRowTurnIds(rows: readonly StoredEventRow[]): string[] {
90	  return Array.from(
91	    new Set(
92	      rows.flatMap((row) => (row.turnId === null ? [] : [row.turnId])),
93	    ),
94	  );
95	}
96	
97	function mergeStoredEventRows(
98	  rows: readonly StoredEventRow[],
99	): StoredEventRow[] {
100	  const rowsBySequence = new Map<number, StoredEventRow>();
101	  for (const row of rows) {
102	    rowsBySequence.set(row.sequence, row);
103	  }
104	  return [...rowsBySequence.values()].sort(
105	    (left, right) => left.sequence - right.sequence,
106	  );
107	}
108	
109	function findTurnRowById(
110	  rows: TimelineRow[],
111	  id: string,
112	): TimelineTurnRow | null {
113	  return (
114	    rows.find(
115	      (row): row is TimelineTurnRow => row.kind === "turn" && row.id === id,
116	    ) ?? null
117	  );
118	}
119	
120	export function toThreadEventWithMeta(
121	  row: StoredEventRow,
122	): ThreadEventWithMeta {
123	  return {
124	    event: parseStoredEvent(row),
125	    meta: {
126	      id: row.id,
127	      seq: row.sequence,
128	      createdAt: row.createdAt,
129	    },
130	  };
131	}
132	
133	function compactSummaryThreadEvents(
134	  events: ThreadEventWithMeta[],
135	): ThreadEventWithMeta[] {
136	  let agentMessageDeltaCount = 0;
137	  const completedAssistantKeys = new Set<string>();
138	  for (const eventWithMeta of events) {
139	    const { event } = eventWithMeta;
140	    if (event.type === "item/agentMessage/delta") {
141	      agentMessageDeltaCount += 1;
142	      continue;
143	    }
144	    if (event.type === "item/completed" && event.item.type === "agentMessage") {
145	      const identity = resolveBufferedTextIdentity({
146	        decoded: event,
147	        kind: "assistant",
148	      });
149	      if (identity) {
150	        completedAssistantKeys.add(createBufferedTextInstanceKey(identity));
151	      }
152	    }
153	  }
154	
155	  if (
156	    agentMessageDeltaCount < MIN_AGENT_MESSAGE_DELTAS_FOR_SUMMARY_COMPACTION ||
157	    completedAssistantKeys.size === 0
158	  ) {
159	    return events;
160	  }
161	
162	  const retainedCompletedDeltaKeys = new Set<string>();
163	  const compactedEvents: ThreadEventWithMeta[] = [];
164	
165	  for (const eventWithMeta of events) {
166	    const { event } = eventWithMeta;
167	    if (event.type !== "item/agentMessage/delta") {
168	      compactedEvents.push(eventWithMeta);
169	      continue;
170	    }
171	
172	    const identity = resolveBufferedTextIdentity({
173	      decoded: event,
174	      kind: "assistant",
175	    });
176	    if (!identity) {
177	      compactedEvents.push(eventWithMeta);
178	      continue;
179	    }
180	
181	    const assistantKey = createBufferedTextInstanceKey(identity);
182	    if (!completedAssistantKeys.has(assistantKey)) {
183	      compactedEvents.push(eventWithMeta);
184	      continue;
185	    }
186	    if (retainedCompletedDeltaKeys.has(assistantKey)) {
187	      continue;
188	    }
189	    retainedCompletedDeltaKeys.add(assistantKey);
190	    compactedEvents.push(eventWithMeta);
191	  }
192	
193	  return compactedEvents;
194	}
195	
196	export function compactSummaryStoredEventRows(
197	  rows: readonly StoredEventRow[],
198	): readonly StoredEventRow[] {
199	  const events = rows.map((row) => toThreadEventWithMeta(row));
200	  const compactedEvents = compactSummaryThreadEvents(events);
201	  if (compactedEvents === events) {
202	    return rows;
203	  }
204	
205	  const retainedEventIds = new Set(
206	    compactedEvents.map((eventWithMeta) => eventWithMeta.meta.id),
207	  );
208	  return rows.filter((row) => retainedEventIds.has(row.id));
209	}
210	
211	function applyTimelineNestedRowsOption(
212	  rows: TimelineRow[],
213	  includeNestedRows: boolean,
214	): TimelineRow[] {
215	  if (includeNestedRows) {
216	    return rows;
217	  }
218	  return rows.map((row) => {
219	    if (row.kind !== "turn") {
220	      return row;
221	    }
222	    return {
223	      ...row,
224	      children: null,
225	    };
226	  });
227	}
228	
229	export function buildThreadTimeline(
230	  db: DbConnection,
231	  thread: Thread,
232	  options: BuildThreadTimelineOptions,
233	): ThreadTimelineResponse {
234	  const includeNestedRows = options.includeNestedRows ?? false;
235	  const includeProviderUnhandledOperations =
236	    options.isDevelopment || options.showAllManagerEvents === true;
237	  const rawEventRows = listRecentStoredEventRows(db, {
238	    threadId: thread.id,
239	    ...(options.showAllManagerEvents === true
240	      ? {}
241	      : { excludedTypes: TIMELINE_NOISE_EVENT_TYPES }),
242	  });
243	  const decodedRawEvents = rawEventRows.map((row) =>
244	    toThreadEventWithMeta(row),
245	  );
246	  const decodedEvents = compactSummaryThreadEvents(decodedRawEvents);
247	  const isDefaultManagerView =
248	    thread.type === "manager" && !options.showAllManagerEvents;
249	  const contextWindowUsageRows = listContextWindowUsageRows(db, {
250	    threadId: thread.id,
251	  });
252	
253	  if (isDefaultManagerView) {
254	    const projection = toViewProjectionEntries(decodedEvents, {
255	      includeInternalSystemMessages: options.showAllManagerEvents,
256	      includeProviderUnhandledOperations,
257	      threadStatus: thread.status,
258	      threadType: thread.type,
259	      turnMessageDetail: "full",
260	    });
261	    return {
262	      rows: buildManagerConversationRows(projection),
263	      activeThinking: null,
264	      contextWindowUsage:
265	        extractThreadContextWindowUsage(
266	          contextWindowUsageRows.map((row) => parseStoredEventRow(row)),
267	        ) ?? undefined,
268	    };
269	  }
270	
271	  const projection = toTimelineProjection(decodedEvents, {
272	    includeInternalSystemMessages: options.showAllManagerEvents,
273	    includeProviderUnhandledOperations,
274	    threadStatus: thread.status,
275	    threadType: thread.type,
276	  });
277	  const rows = applyTimelineNestedRowsOption(
278	    buildTimelineRowsFromProjection({ projection }),
279	    includeNestedRows,
280	  );
281	
282	  return {
283	    rows,
284	    activeThinking: projection.state.activeThinking,
285	    contextWindowUsage:
286	      extractThreadContextWindowUsage(
287	        contextWindowUsageRows.map((row) => parseStoredEventRow(row)),
288	      ) ?? undefined,
289	  };
290	}
291	
292	export function buildTimelineTurnSummaryDetails(
293	  db: DbConnection,
294	  thread: Thread,
295	  options: BuildTimelineTurnSummaryDetailsOptions,
296	): TimelineTurnSummaryDetailsResponse {
297	  const includeProviderUnhandledOperations =
298	    options.isDevelopment || options.showAllManagerEvents === true;
299	  const exactEventRows = listStoredEventRowsInRange(db, {
300	    threadId: thread.id,
301	    seqStart: options.sourceSeqStart,
302	    seqEnd: options.sourceSeqEnd,
303	  });
304	  const turnScopedRows = listStoredTurnScopedEventRowsByTurnIds(db, {
305	    threadId: thread.id,
306	    turnIds: getEventRowTurnIds(exactEventRows),
307	  });
308	  const clientRequestSequences = Array.from(
309	    new Set(
310	      exactEventRows.flatMap((row) =>
311	        row.type === "client/turn/requested" ? [row.sequence] : [],
312	      ),
313	    ),
314	  );
315	  const acceptedInputRows =
316	    listStoredTurnInputAcceptedRowsByClientRequestSequences(db, {
317	      threadId: thread.id,
318	      afterSequence: options.sourceSeqEnd,
319	      clientRequestSequences,
320	    });
321	  const projectionRows = mergeStoredEventRows([
322	    ...turnScopedRows,
323	    ...exactEventRows,
324	    ...acceptedInputRows,
325	  ]);
326	  const projection = toTimelineProjection(
327	    projectionRows.map((row) => toThreadEventWithMeta(row)),
328	    {
329	      includeInternalSystemMessages: options.showAllManagerEvents,
330	      includeProviderUnhandledOperations,
331	      threadStatus: thread.status,
332	      threadType: thread.type,
333	    },
334	  );
335	  const rows = buildTimelineRowsFromProjection({ projection });
336	  const turnRow = findTurnRowById(rows, options.turnSummaryId);
337	  if (turnRow) {
338	    return {
339	      rows: turnRow.children ?? [],
340	    };
341	  }
342	  if (rows.length === 0) {
343	    return {
344	      rows,
345	    };
346	  }
347	
348	  throw new Error(
349	    `Timeline turn summary details could not match ${options.turnSummaryId}`,
350	  );
351	}
