23	describe("timeline source projection", () => {
24	  it("splits a provider fileChange item into one file-change work row per changed file", () => {
25	    const event = createTimelineEventFactory({
26	      threadId: "thread-1",
27	      turnId: "turn-1",
28	    });
29	
30	    const projection = toTimelineProjection(
31	      fromRows([
32	        event.turnStarted(),
33	        event.fileChangeCompleted({
34	          itemId: "phase-files-a",
35	          changes: [
36	            {
37	              path: "apps/app/src/views/appSettingsAtoms.ts",
38	              kind: "add",
39	              diff: "+export const appSettingsAtom = atom({});",
40	            },
41	            {
42	              path: "apps/app/src/views/projectSettingsAtoms.ts",
43	              kind: "add",
44	              diff: "+export const projectSettingsAtom = atom({});",
45	            },
46	            {
47	              path: "apps/app/src/views/promptComposerAtoms.ts",
48	              kind: "add",
49	              diff: "+export const promptComposerAtom = atom({});",
50	            },
51	          ],
52	        }),
53	        event.turnCompleted(),
54	      ]),
55	      {
56	        threadStatus: "idle",
57	      },
58	    );
59	
60	    const fileRows = projection.rows.filter(isFileChangeWorkRow);
61	
62	    expect(fileRows).toEqual([
63	      expect.objectContaining({
64	        workKind: "file-change",
65	        action: "created",
66	        path: "apps/app/src/views/appSettingsAtoms.ts",
67	        displayName: "appSettingsAtoms.ts",
68	      }),
69	      expect.objectContaining({
70	        workKind: "file-change",
71	        action: "created",
72	        path: "apps/app/src/views/projectSettingsAtoms.ts",
73	        displayName: "projectSettingsAtoms.ts",
74	      }),
75	      expect.objectContaining({
76	        workKind: "file-change",
77	        action: "created",
78	        path: "apps/app/src/views/promptComposerAtoms.ts",
79	        displayName: "promptComposerAtoms.ts",
80	      }),
81	    ]);
82	  });
83	
84	  it("keeps pending file-change approvals visible before diffs arrive", () => {
85	    const event = createTimelineEventFactory({
86	      threadId: "thread-1",
87	      turnId: "turn-1",
88	    });
