115	          removed: 0,
116	        },
117	        diff: null,
118	        status: "pending",
119	        approvalStatus: "waiting_for_approval",
120	      }),
121	    ]);
122	  });
123	
124	  it("projects read-like tool activity as read work rows", () => {
125	    const event = createTimelineEventFactory({
126	      threadId: "thread-1",
127	      turnId: "turn-1",
128	    });
129	
