387	export function flattenProjectionMessages(
388	  projection: ViewProjection,
389	): ViewMessage[] {
390	  const messages: ViewMessage[] = [];
391	  for (const entry of projection.entries) {
392	    if (entry.kind === "message") {
393	      messages.push(entry.message);
394	      continue;
395	    }
396	    if (entry.turn.messages) {
397	      messages.push(...entry.turn.messages);
398	      continue;
399	    }
400	    if (entry.turn.terminalMessage) {
401	      messages.push(entry.turn.terminalMessage);
402	    }
403	  }
404	  return messages;
405	}
406	
407	export function unique<T>(values: T[]): T[] {
408	  return [...new Set(values)];
409	}
410	
411	export function assertMonotonicSourceSeq(messages: ViewMessage[]): void {
412	  for (let i = 1; i < messages.length; i += 1) {
413	    const prev = messages[i - 1];
414	    const next = messages[i];
415	    expect(prev).toBeDefined();
416	    expect(next).toBeDefined();
417	    if (!prev || !next) continue;
418	    expect(next.sourceSeqStart).toBeGreaterThanOrEqual(prev.sourceSeqStart);
419	  }
420	}
