422	function withExplicitApprovalStatus(row: ThreadEventRow): ThreadEventRow {
423	  if (row.type !== "item/started" && row.type !== "item/completed") {
424	    return row;
425	  }
426	
427	  const item = row.data.item;
428	  if (item.type !== "commandExecution" && item.type !== "fileChange") {
429	    return row;
430	  }
431	  if (item.approvalStatus !== undefined) {
432	    return row;
433	  }
434	
435	  return {
436	    ...row,
437	    data: {
438	      ...row.data,
439	      item: {
440	        ...item,
441	        approvalStatus: null,
442	      },
443	    },
444	  };
445	}
