1051	export function renderTimelineFixture(
1052	  args: RenderTimelineFixtureArgs,
1053	): RenderedTimelineFixture {
1054	  const decodedEvents = args.events.map((row) => decodeRow(row));
1055	  const projection = toViewProjection(decodedEvents, args.projectionOptions);
1056	  const timelineProjection = toTimelineProjection(
1057	    decodedEvents,
1058	    args.projectionOptions,
1059	  );
1060	  const rows = resolveFixtureRows({
1061	    includeNestedRows: args.includeToolGroupMessages ?? true,
1062	    rows: buildTimelineRowsFromProjection({ projection: timelineProjection }),
1063	  });
1064	  const messages = flattenProjectionMessagesDeep(projection);
1065	  const text = formatTimelineAsText(rows, {
1066	    verbose: args.verbose ?? true,
1067	  });
1068	  const toolGroups = collectTimelineGroupRows(rows);
1069	
1070	  return {
1071	    events: args.events,
1072	    messages,
1073	    projection,
1074	    rows,
1075	    text,
1076	    toolGroups,
1077	  };
1078	}
