1080	interface ResolveFixtureRowsArgs {
1081	  includeNestedRows: boolean;
1082	  rows: readonly TimelineRow[];
1083	}
1084	
1085	function resolveFixtureRows({
1086	  includeNestedRows,
1087	  rows,
1088	}: ResolveFixtureRowsArgs): TimelineRow[] {
1089	  if (includeNestedRows) {
1090	    return [...rows];
1091	  }
1092	  return rows.map((row) =>
1093	    row.kind === "turn"
1094	      ? {
1095	          ...row,
1096	          children: null,
1097	        }
1098	      : row,
1099	  );
1100	}
1101	
1102	function collectTimelineGroupRows(
1103	  rows: readonly TimelineRow[],
1104	): TimelineGroupRow[] {
1105	  const groups: TimelineGroupRow[] = [];
1106	  for (const row of rows) {
1107	    if (row.kind === "group") {
1108	      groups.push(row);
1109	      continue;
1110	    }
1111	    if (row.kind === "turn" && row.children) {
1112	      groups.push(...collectTimelineGroupRows(row.children));
1113	    }
1114	  }
1115	  return groups;
1116	}
