1146	function appendLogicalRowsFromTimelineRow(
1147	  args: AppendResolvedLogicalRowArgs,
1148	): void {
1149	  appendResolvedLogicalRow(args);
1150	
1151	  switch (args.timelineRow.kind) {
1152	    case "conversation":
1153	    case "system":
1154	    case "work":
1155	      return;
1156	    case "group":
1157	      for (const childRow of args.timelineRow.children) {
1158	        appendLogicalRowsFromTimelineRow({
1159	          rows: args.rows,
1160	          timelineRow: childRow,
1161	          resolveRow: args.resolveRow,
1162	        });
1163	      }
1164	      return;
1165	    case "turn":
1166	      if (!args.timelineRow.children) {
1167	        return;
1168	      }
1169	      for (const childRow of args.timelineRow.children) {
1170	        appendLogicalRowsFromTimelineRow({
1171	          rows: args.rows,
1172	          timelineRow: childRow,
1173	          resolveRow: args.resolveRow,
1174	        });
1175	      }
1176	      return;
