1196	export function expectTerminalRowsNeverRegress(
1197	  args: PrefixTerminalStabilityArgs,
1198	): void {
1199	  const terminalByKey = new Map<string, TerminalRowSnapshot>();
1200	  const prefixes = renderTimelinePrefixes(args);
1201	
1202	  for (const prefix of prefixes) {
1203	    const currentRowsByKey = new Map<string, LogicalTimelineRow>();
1204	    for (const logicalRow of collectLogicalTimelineRows({
1205	      rows: prefix.rows,
1206	      resolveRow: args.resolveRow,
1207	    })) {
1208	      currentRowsByKey.set(logicalRow.key, logicalRow);
1209	    }
1210	
1211	    for (const previous of terminalByKey.values()) {
1212	      const current = currentRowsByKey.get(previous.key);
1213	      if (!current) {
1214	        throw new Error(
1215	          `Terminal row ${previous.key} disappeared after prefix ${previous.prefixLength}`,
1216	        );
1217	      }
1218	      expect(current.status).toBe(previous.status);
1219	      expect(current.title).toBe(previous.title);
1220	    }
1221	
1222	    for (const current of currentRowsByKey.values()) {
1223	      if (isTerminalStatus(current.status) && !terminalByKey.has(current.key)) {
1224	        terminalByKey.set(current.key, {
1225	          ...current,
1226	          prefixLength: prefix.events.length,
1227	        });
1228	      }
1229	    }
1230	  }
1231	}
