4	import {
5	  type ToViewMessagesOptions,
6	  type ViewMessage,
7	  type ViewTasksMessage,
8	  type ViewUserMessage,
9	  viewTasksMessageSchema,
10	  viewUserMessageSchema,
11	} from "./ui-message.js";
12	
13	export const viewTurnStatusValues = [
14	  "pending",
15	  "completed",
16	  "error",
17	  "interrupted",
18	] as const;
19	export const viewTurnStatusSchema = z.enum(viewTurnStatusValues);
20	export type ViewTurnStatus = z.infer<typeof viewTurnStatusSchema>;
21	
22	export const viewTurnMessageDetailValues = ["summary", "full"] as const;
23	export const viewTurnMessageDetailSchema = z.enum(viewTurnMessageDetailValues);
24	/**
25	 * Controls how eagerly completed turns include their message arrays.
26	 * Summary projections may still include messages when row ordering,
27	 * ungroupable messages, or nested delegation projections need them.
28	 */
29	export type ViewTurnMessageDetail = z.infer<typeof viewTurnMessageDetailSchema>;
30	
31	export interface ViewProjectionState {
32	  /**
33	   * Root-projection-only ephemeral state that should not be modeled as a
34	   * timeline row. Nested child projections always expose `activeThinking` as
35	   * null because only the thread-level timeline owns live thinking state.
36	   */
37	  activeThinking: ActiveThinking | null;
38	  /**
39	   * Root-projection-only steer requests that have not been accepted by a
40	   * provider turn yet. Timeline row builders append them after durable entries.
41	   */
42	  pendingUserSteers: ViewUserMessage[];
43	  /**
44	   * Parsed task updates that are intentionally outside the timeline row stream.
45	   * Historical task events remain replayable here while the timeline ignores them.
46	   */
47	  tasks: ViewTasksMessage[];
48	}
49	
50	export const viewProjectionStateSchema = z.object({
51	  activeThinking: activeThinkingSchema.nullable(),
52	  pendingUserSteers: z.array(viewUserMessageSchema),
53	  tasks: z.array(viewTasksMessageSchema),
54	});
55	
56	export interface ToViewProjectionOptions extends ToViewMessagesOptions {
57	  turnMessageDetail: ViewTurnMessageDetail;
58	}
59	
60	export type ViewTimelineEntry =
61	  | ViewStandaloneTimelineEntry
62	  | ViewTurnTimelineEntry;
63	
64	export interface ViewStandaloneTimelineEntry {
65	  kind: "message";
66	  message: ViewMessage;
67	}
68	
69	export interface ViewTurnTimelineEntry {
70	  kind: "turn";
71	  turn: ViewTurn;
72	}
73	
74	export interface ViewTurn {
75	  turnId: string;
76	  threadId: string;
77	  sourceSeqStart: number;
78	  sourceSeqEnd: number;
79	  startedAt: number;
80	  createdAt: number;
81	  completedAt: number | null;
82	  status: ViewTurnStatus;
83	  summaryCount: number;
