85	  summaryAnchorMessageId?: string;
86	  /** Present for completed turns; non-positive measured durations are clamped to 0. */
87	  durationMs?: number;
88	  terminalMessage?: ViewMessage;
89	  messages?: ViewMessage[];
90	}
91	
92	export interface ViewProjection {
93	  entries: ViewTimelineEntry[];
94	  /** Projection-owned live state derived during the same event pass as entries. */
95	  state: ViewProjectionState;
96	}
