{"jsonrpc":"2.0","method":"sdk/message","params":{"threadId":"thr_2mp6rkmsxy","message":{"type":"user","message":{"role":"user","content":[{"tool_use_id":"toolu_015j7nDbw9QJcWYZ5A2WwBtD","type":"tool_result","content":"120	
121	function getWorkGroupBounds(children: TimelineWorkRow[]): WorkGroupBounds {
122	  const first = children[0];
123	  const last = children[children.length - 1];
124	  if (!first || !last) {
125	    throw new Error("Cannot build an empty timeline work group");
126	  }
127	
128	  let createdAt = first.createdAt;
129	  let sourceSeqEnd = first.sourceSeqEnd;
130	  let sourceSeqStart = first.sourceSeqStart;
131	  let startedAt = first.startedAt;
132	  let turnId = first.turnId;
133	
134	  for (const child of children) {
135	    createdAt = Math.max(createdAt, child.createdAt);
136	    sourceSeqEnd = Math.max(sourceSeqEnd, child.sourceSeqEnd);
137	    sourceSeqStart = Math.min(sourceSeqStart, child.sourceSeqStart);
138	    startedAt = Math.min(startedAt, child.startedAt);
139	    if (turnId !== child.turnId) {
140	      turnId = null;
141	    }
142	  }
143	
144	  return {
145	    threadId: first.threadId,
146	    turnId,
147	    sourceSeqStart,
148	    sourceSeqEnd,
149	    startedAt,
150	    createdAt,
151	  };
152	}
153	
154	function buildGroupId({
155	  children,
156	  groupKind,
157	  groupOrdinal,
158	  semanticKind,
159	}: BuildGroupRowArgs): string {
160	  const bounds = getWorkGroupBounds(children);
161	  const semanticIdPart = semanticKind ?? "step";
162	  return [
163	    bounds.threadId,
164	    bounds.turnId ?? "thread",
165	    "group",
166	    groupKind,
167	    semanticIdPart,
168	    String(bounds.sourceSeqStart),
169	    String(bounds.sourceSeqEnd),
170	    String(groupOrdinal),
171	  ].join(":");
172	}
173	
174	function buildGroupBase(args: BuildGroupRowArgs): TimelineRowBase {
175	  const bounds = getWorkGroupBounds(args.children);
176	  return {
177	    id: buildGroupId(args),
178	    threadId: bounds.threadId,
179	    turnId: bounds.turnId,
180	    sourceSeqStart: bounds.sourceSeqStart,
181	    sourceSeqEnd: bounds.sourceSeqEnd,
182	    startedAt: bounds.startedAt,
183	    createdAt: bounds.createdAt,
184	  };
185	}
186	
187	function buildStepSummaryGroup(args: BuildGroupRowArgs): TimelineGroupRow {
188	  return {
189	    ...buildGroupBase(args),
190	    kind: "group",
191	    groupKind: "step-summary",
192	    semanticKind: null,
193	    children: args.children,
194	  };
195	}
