197	function buildSemanticBundleGroup(args: BuildGroupRowArgs): TimelineGroupRow {
198	  if (args.semanticKind === null) {
199	    throw new Error("Cannot build a semantic timeline bundle without a kind");
200	  }
201	  return {
202	    ...buildGroupBase(args),
203	    kind: "group",
204	    groupKind: "semantic-bundle",
205	    semanticKind: args.semanticKind,
206	    children: args.children,
207	  };
208	}
