210	function getWorkSemanticKind(row: TimelineWorkRow): TimelineSemanticKind {
211	  switch (row.workKind) {
212	    case "command":
213	      return "commands";
214	    case "delegation":
215	      return "delegations";
216	    case "file-change":
217	      return "file-changes";
218	    case "list":
