232	function flushSemanticRun(
233	  rows: TimelineRow[],
234	  run: TimelineWorkRow[],
235	  semanticKind: TimelineSemanticKind,
236	  groupOrdinal: number,
237	): number {
238	  if (run.length > 1 && SEMANTIC_BUNDLE_KINDS.has(semanticKind)) {
239	    rows.push(
