121	function getWorkGroupBounds(children: TimelineWorkRow[]): WorkGroupBounds {
122	  const first = children[0];
123	  const last = children[children.length - 1];
124	  if (!first || !last) {
125	    throw new Error("Cannot build an empty timeline work group");
126	  }
127	
128	  let createdAt = first.createdAt;
129	  let sourceSeqEnd = first.sourceSeqEnd;
130	  let sourceSeqStart = first.sourceSeqStart;
131	  let startedAt = first.startedAt;
132	  let turnId = first.turnId;
133	
134	  for (const child of children) {
135	    createdAt = Math.max(createdAt, child.createdAt);
136	    sourceSeqEnd = Math.max(sourceSeqEnd, child.sourceSeqEnd);
137	    sourceSeqStart = Math.min(sourceSeqStart, child.sourceSeqStart);
138	    startedAt = Math.min(startedAt, child.startedAt);
