133	function compactSummaryThreadEvents(
134	  events: ThreadEventWithMeta[],
135	): ThreadEventWithMeta[] {
136	  let agentMessageDeltaCount = 0;
137	  const completedAssistantKeys = new Set<string>();
138	  for (const eventWithMeta of events) {
139	    const { event } = eventWithMeta;
140	    if (event.type === "item/agentMessage/delta") {
141	      agentMessageDeltaCount += 1;
142	      continue;
143	    }
144	    if (event.type === "item/completed" && event.item.type === "agentMessage") {
145	      const identity = resolveBufferedTextIdentity({
146	        decoded: event,
147	        kind: "assistant",
