244	    toThreadEventWithMeta(row),
245	  );
246	  const decodedEvents = compactSummaryThreadEvents(decodedRawEvents);
247	  const isDefaultManagerView =
248	    thread.type === "manager" && !options.showAllManagerEvents;
249	  const contextWindowUsageRows = listContextWindowUsageRows(db, {
250	    threadId: thread.id,
251	  });
252	
253	  if (isDefaultManagerView) {
254	    const projection = toViewProjectionEntries(decodedEvents, {
255	      includeInternalSystemMessages: options.showAllManagerEvents,
256	      includeProviderUnhandledOperations,
257	      threadStatus: thread.status,
258	      threadType: thread.type,
259	      turnMessageDetail: "full",
260	    });
261	    return {
262	      rows: buildManagerConversationRows(projection),
263	      activeThinking: null,
264	      contextWindowUsage:
265	        extractThreadContextWindowUsage(
266	          contextWindowUsageRows.map((row) => parseStoredEventRow(row)),
267	        ) ?? undefined,
268	    };
269	  }
270	
271	  const projection = toTimelineProjection(decodedEvents, {
272	    includeInternalSystemMessages: options.showAllManagerEvents,
273	    includeProviderUnhandledOperations,
274	    threadStatus: thread.status,
275	    threadType: thread.type,
276	  });
277	  const rows = applyTimelineNestedRowsOption(
278	    buildTimelineRowsFromProjection({ projection }),
279	    includeNestedRows,
280	  );
