296	): TimelineTurnSummaryDetailsResponse {
297	  const includeProviderUnhandledOperations =
298	    options.isDevelopment || options.showAllManagerEvents === true;
299	  const exactEventRows = listStoredEventRowsInRange(db, {
300	    threadId: thread.id,
301	    seqStart: options.sourceSeqStart,
302	    seqEnd: options.sourceSeqEnd,
303	  });
304	  const turnScopedRows = listStoredTurnScopedEventRowsByTurnIds(db, {
305	    threadId: thread.id,
306	    turnIds: getEventRowTurnIds(exactEventRows),
307	  });
308	  const clientRequestSequences = Array.from(
309	    new Set(
310	      exactEventRows.flatMap((row) =>
311	        row.type === "client/turn/requested" ? [row.sequence] : [],
312	      ),
313	    ),
314	  );
315	  const acceptedInputRows =
316	    listStoredTurnInputAcceptedRowsByClientRequestSequences(db, {
317	      threadId: thread.id,
318	      afterSequence: options.sourceSeqEnd,
319	      clientRequestSequences,
320	    });
321	  const projectionRows = mergeStoredEventRows([
322	    ...turnScopedRows,
323	    ...exactEventRows,
324	    ...acceptedInputRows,
325	  ]);
326	  const projection = toTimelineProjection(
327	    projectionRows.map((row) => toThreadEventWithMeta(row)),
328	    {
329	      includeInternalSystemMessages: options.showAllManagerEvents,
330	      includeProviderUnhandledOperations,
331	      threadStatus: thread.status,
332	      threadType: thread.type,
333	    },
334	  );
335	  const rows = buildTimelineRowsFromProjection({ projection });
336	  const turnRow = findTurnRowById(rows, options.turnSummaryId);
337	  if (turnRow) {
338	    return {
339	      rows: turnRow.children ?? [],
340	    };
341	  }
342	  if (rows.length === 0) {
343	    return {
344	      rows,
345	    };
346	  }
347	
348	  throw new Error(
349	    `Timeline turn summary details could not match ${options.turnSummaryId}`,
350	  );
