121	            key={ongoingIndicatorKey}
122	            details={activeThinkingDetails}
123	            isThinking={showActiveThinking}
124	            label={ongoingIndicatorLabel}
125	          />
126	        ) : null}
127	      </PageShell>
128	    </div>
129	  );
130	}
