132	// Delay before revealing the loading indicator so fast loads don't flash.
133	const LOADING_INDICATOR_REVEAL_DELAY_MS = 200;
134	
135	function DelayedThreadLoadingIndicator() {
136	  const [visible, setVisible] = useState(false);
137	  useEffect(() => {
138	    const id = window.setTimeout(
139	      () => setVisible(true),
140	      LOADING_INDICATOR_REVEAL_DELAY_MS,
141	    );
142	    return () => window.clearTimeout(id);
143	  }, []);
144	
145	  if (!visible) {
146	    return null;
147	  }
148	
149	  return (
150	    <ConversationWorkingIndicator label="Loading thread..." className="mt-6" />
151	  );
152	}
