646	function collectGroupRows(rows: readonly TimelineRow[]): TimelineGroupRow[] {
647	  const groups: TimelineGroupRow[] = [];
648	  for (const row of rows) {
649	    if (row.kind === "group") {
650	      groups.push(row);
651	    }
652	    if (row.kind === "turn" && row.children) {
653	      groups.push(...collectGroupRows(row.children));
654	    }
655	  }
656	  return groups;
657	}
