659	function collectWorkRows(rows: readonly TimelineRow[]): TimelineWorkRow[] {
660	  const workRows: TimelineWorkRow[] = [];
661	  for (const row of rows) {
662	    if (row.kind === "work") {
663	      workRows.push(row);
664	      if (row.workKind === "delegation") {
665	        workRows.push(...collectWorkRows(row.childRows));
666	      }
667	    }
668	    if (row.kind === "group") {
669	      workRows.push(...row.children);
670	    }
671	    if (row.kind === "turn" && row.children) {
672	      workRows.push(...collectWorkRows(row.children));
673	    }
674	  }
675	  return workRows;
676	}
