678	function collectTimelineRowIds(rows: ReadonlyTimelineRows): string[] {
679	  const ids: string[] = [];
680	  for (const row of rows) {
681	    ids.push(row.id);
682	    switch (row.kind) {
683	      case "conversation":
684	      case "system":
685	        break;
686	      case "group":
687	        ids.push(...collectTimelineRowIds(row.children));
688	        break;
689	      case "turn":
690	        if (row.children) {
691	          ids.push(...collectTimelineRowIds(row.children));
692	        }
693	        break;
694	      case "work":
695	        if (row.workKind === "delegation") {
696	          ids.push(...collectTimelineRowIds(row.childRows));
697	        }
698	        break;
699	    }
700	  }
701	  return ids;
702	}
