40	function unwrapQuotedShellArg(value: string): string {
41	  if (value.length < 2) return value;
42	  const quote = value[0];
43	  if ((quote !== "'" && quote !== '"') || value[value.length - 1] !== quote) {
44	    return value;
45	  }
46	  const inner = value.slice(1, -1);
47	  if (quote === "'") return inner;
48	
49	  // POSIX double-quote: backslash escapes $, `, ", \, and newline. Any other
50	  // backslash is preserved literally. Unescaping here restores the inner
51	  // command to a form the tokenizer can parse without tripping over
52	  // shell-wrapper-only escapes.
53	  let result = "";
54	  for (let i = 0; i < inner.length; i += 1) {
55	    const ch = inner[i];
56	    if (ch === "\\" && i + 1 < inner.length) {
57	      const next = inner[i + 1]!;
58	      if (
59	        next === "$" ||
60	        next === "`" ||
61	        next === '"' ||
62	        next === "\\" ||
63	        next === "\n"
64	      ) {
65	        result += next;
66	        i += 1;
67	        continue;
68	      }
69	    }
70	    result += ch;
71	  }
72	  return result;
73	}
