88	  const match = /^(\S+)\s+(-lc|-c)\s+([\s\S]+)$/.exec(trimmed);
89	  if (!match) return trimmed;
90	
91	  const shellProgram = match[1];
92	  const commandArg = match[3];
93	  if (!shellProgram || !commandArg || !isKnownShellWrapper(shellProgram)) {
94	    return trimmed;
95	  }
96	
97	  return unwrapQuotedShellArg(commandArg.trim());
