341	// Characters that a backslash may escape inside double quotes, per POSIX shell
342	// semantics. A backslash before any other character is preserved literally.
343	const DOUBLE_QUOTE_ESCAPABLE = new Set(["$", "`", '"', "\\", "\n"]);
344	
345	/** A shell token carries its literal value and whether any portion of it
346	 * came from inside a quoted string. The `quoted` flag lets the redirect
347	 * classifier distinguish operator-shaped characters that originated as shell
348	 * operators from ones the user typed inside quotes. */
349	export interface ShellToken {
350	  readonly value: string;
351	  readonly quoted: boolean;
352	}
353	
354	export function tokenizeShellWords(command: string): ShellToken[] {
355	  const tokens: ShellToken[] = [];
356	  let current = "";
357	  // Track quoted vs unquoted contributions to the current token separately.
358	  // A token is `quoted: true` only when *every* character originated inside
359	  // quotes — that way `"-n"` (fully quoted) is recognized as a literal, while
360	  // `--include='*.html'` (partially quoted) is still treated as a flag.
361	  let currentHasQuoted = false;
362	  let currentHasUnquoted = false;
363	  let quote: "'" | '"' | null = null;
364	  let escaping = false;
365	
366	  const recordQuoted = (): void => {
367	    currentHasQuoted = true;
368	  };
369	  const recordUnquoted = (): void => {
370	    currentHasUnquoted = true;
371	  };
372	
373	  const flushCurrent = (): void => {
374	    const fullyQuoted = currentHasQuoted && !currentHasUnquoted;
375	    const hasContent = current.length > 0;
376	    if (!hasContent && !fullyQuoted) {
377	      currentHasQuoted = false;
378	      currentHasUnquoted = false;
379	      return;
380	    }
381	    tokens.push({ value: current, quoted: fullyQuoted });
382	    current = "";
383	    currentHasQuoted = false;
384	    currentHasUnquoted = false;
385	  };
386	
387	  for (let index = 0; index < command.length; index += 1) {
388	    const character = command[index];
389	    if (!character) continue;
390	
391	    if (escaping) {
392	      current += character;
393	      if (quote !== null) recordQuoted();
394	      else recordUnquoted();
395	      escaping = false;
396	      continue;
397	    }
398	
399	    if (character === "\\") {
400	      if (quote === "'") {
401	        current += character;
402	        recordQuoted();
403	        continue;
404	      }
405	      if (quote === '"') {
406	        const next = command[index + 1];
407	        if (next === undefined || !DOUBLE_QUOTE_ESCAPABLE.has(next)) {
408	          current += character;
409	          recordQuoted();
410	          continue;
411	        }
412	      }
413	      escaping = true;
414	      continue;
415	    }
416	
417	    if (quote) {
418	      if (character === quote) {
419	        quote = null;
420	        // An empty quoted string (`""` / `''`) still produces a token.
421	        if (current.length === 0) recordQuoted();
422	        continue;
423	      }
424	      current += character;
425	      recordQuoted();
426	      continue;
427	    }
428	
429	    if (character === "'" || character === '"') {
430	      quote = character;
431	      continue;
432	    }
433	
434	    if (/\s/u.test(character)) {
435	      flushCurrent();
436	      continue;
437	    }
438	
439	    if (character === "|" || character === "&" || character === ";") {
440	      // `&>` / `&>>` are stdout+stderr redirects, not a background `&` followed
441	      // by redirection. Build them as a compound operator.
442	      if (character === "&" && command[index + 1] === ">") {
443	        flushCurrent();
444	        if (command[index + 2] === ">") {
445	          tokens.push({ value: "&>>", quoted: false });
446	          index += 2;
447	        } else {
448	          tokens.push({ value: "&>", quoted: false });
449	          index += 1;
450	        }
451	        continue;
452	      }
453	
454	      flushCurrent();
455	
456	      const nextCharacter = command[index + 1];
457	      if (
458	        nextCharacter &&
459	        ((character === "|" && nextCharacter === "|") ||
460	          (character === "&" && nextCharacter === "&"))
461	      ) {
462	        tokens.push({ value: `${character}${nextCharacter}`, quoted: false });
463	        index += 1;
464	        continue;
465	      }
466	
467	      tokens.push({ value: character, quoted: false });
468	      continue;
469	    }
470	
471	    if (character === "<" || character === ">") {
472	      // The `<` and `>` family of operators. If the current buffer is exactly
473	      // a digit sequence or `&` and was built entirely outside quotes, treat
474	      // it as the file-descriptor prefix for this redirect (e.g. `2>`, `&>`);
475	      // otherwise flush current as a word.
476	      let prefix = "";
477	      const currentIsUnquoted = currentHasUnquoted && !currentHasQuoted;
478	      if (currentIsUnquoted && (current === "&" || /^\d+$/u.test(current))) {
479	        prefix = current;
480	        current = "";
481	        currentHasUnquoted = false;
482	      } else if (current.length > 0 || currentHasQuoted) {
483	        flushCurrent();
484	      }
485	
486	      const next1 = command[index + 1];
487	      const next2 = command[index + 2];
488	
489	      let op = character;
490	      let consumed = 1;
491	
492	      if (character === ">") {
493	        if (next1 === ">") {
494	          op = ">>";
495	          consumed = 2;
496	        } else if (next1 === "|") {
497	          op = ">|";
498	          consumed = 2;
499	        } else if (next1 === "(") {
500	          op = ">(";
501	          consumed = 2;
502	        } else if (next1 === "&") {
503	          op = ">&";
504	          consumed = 2;
505	        }
506	      } else {
507	        if (next1 === "<" && next2 === "<") {
508	          op = "<<<";
509	          consumed = 3;
510	        } else if (next1 === "<" && next2 === "-") {
511	          op = "<<-";
512	          consumed = 3;
513	        } else if (next1 === "<") {
514	          op = "<<";
515	          consumed = 2;
516	        } else if (next1 === "(") {
517	          op = "<(";
518	          consumed = 2;
519	        } else if (next1 === ">") {
520	          op = "<>";
521	          consumed = 2;
522	        }
523	      }
524	
525	      tokens.push({ value: `${prefix}${op}`, quoted: false });
526	      index += consumed - 1;
527	      continue;
528	    }
529	
530	    current += character;
531	    recordUnquoted();
532	  }
533	
534	  if (escaping) {
535	    current += "\\";
536	    recordUnquoted();
537	  }
538	  flushCurrent();
539	
540	  return tokens;
541	}
