556	/** Search flags that take a separate value. */
557	const SEARCH_FLAGS_WITH_VALUE: ReadonlySet<string> = new Set([
558	  "-g",
559	  "--glob",
560	  "-t",
561	  "--type",
562	  "-T",
563	  "--type-not",
564	  "-A",
565	  "--after-context",
566	  "-B",
567	  "--before-context",
568	  "-C",
569	  "--context",
570	  "-m",
571	  "--max-count",
572	]);
573	
574	/** `find` flags whose value is the next token. Only the common ones —
575	 * unknown flags are treated as value-less, which is harmless for path extraction
576	 * since `find` puts the start path before the expression. */
577	const FIND_FLAGS_WITH_VALUE: ReadonlySet<string> = new Set([
578	  "-name",
579	  "-iname",
580	  "-path",
581	  "-ipath",
582	  "-type",
583	  "-maxdepth",
584	  "-mindepth",
585	  "-size",
586	  "-mtime",
587	  "-mmin",
588	  "-user",
589	  "-group",
590	  "-perm",
591	  "-regex",
592	  "-iregex",
593	]);
594	
595	const HEAD_TAIL_FLAGS_WITH_VALUE: ReadonlySet<string> = new Set(["-n", "-c"]);
596	const NO_FLAGS_WITH_VALUE: ReadonlySet<string> = new Set();
