598	type SegmentClassification =
599	  | { kind: "write" }
600	  | { kind: "intent"; intent: ViewToolParsedIntent }
601	  | { kind: "none" };
602	
603	interface RedirectScan {
604	  /** True when the redirect targets a real file (content is being written). */
605	  isWrite: boolean;
606	  /** Extra tokens consumed past the redirect operator (e.g., the target). */
607	  consumedExtra: number;
608	}
