610	function baseExecutableName(token: string): string {
611	  const slash = token.lastIndexOf("/");
612	  return slash >= 0 ? token.slice(slash + 1) : token;
613	}
614	
615	/** Matches `-i`, `-i.bak`, `-iEXT`, `--in-place`, `--in-place=EXT`. */
616	function isSedInPlaceFlag(token: string): boolean {
617	  if (token === "--in-place") return true;
618	  if (token.startsWith("--in-place=")) return true;
619	  return /^-i(?:$|[^-])/u.test(token);
620	}
