622	/** Splits a command string into per-segment token lists, using `&&`, `||`,
623	 * `|`, and `;` as segment boundaries. Quoted operator-shaped tokens are never
624	 * treated as segment breaks (a quoted `|` is just a literal pipe character). */
625	function splitShellCommandSegments(command: string): ShellToken[][] {
626	  const tokens = tokenizeShellWords(command);
627	  const segments: ShellToken[][] = [];
628	  let current: ShellToken[] = [];
629	  for (const token of tokens) {
630	    if (!token.quoted && SHELL_SEGMENT_BREAK_TOKENS.has(token.value)) {
631	      if (current.length > 0) {
632	        segments.push(current);
633	        current = [];
634	      }
635	      continue;
636	    }
637	    current.push(token);
638	  }
639	  if (current.length > 0) segments.push(current);
640	  return segments;
641	}
