643	/** Identifies a redirect at `tokens[index]` and reports whether it represents
644	 * a file write. Returns `null` when the token is not a redirect at all.
645	 *
646	 * Token shapes (produced by `tokenizeShellWords`): all redirect operators are
647	 * separate tokens, optionally prefixed by a digit-fd or `&`. Examples:
648	 * `>`, `>>`, `1>`, `2>`, `&>`, `&>>`, `>|`, `>&`, `>(`, `<`, `<<`, `<<-`,
649	 * `<<<`, `<(`, `<>`. Targets always follow as their own tokens. */
650	function scanRedirectAt(
651	  tokens: readonly ShellToken[],
652	  index: number,
653	): RedirectScan | null {
654	  const token = tokens[index];
655	  if (token === undefined) return null;
656	  // Quoted operator-shaped tokens (e.g. `grep ">" file`) are literal data, not
657	  // shell operators; never classify them as redirects.
658	  if (token.quoted) return null;
659	
660	  const value = token.value;
661	  const nextValue = tokens[index + 1]?.value;
662	
663	  // Heredoc body marker: `<<` / `<<-`. Always a write-shape (the command is
664	  // mutating something downstream of stdin). Next token is the delimiter.
665	  if (/^(?:\d+|&)?<<-?$/u.test(value)) {
666	    return { isWrite: true, consumedExtra: 1 };
667	  }
668	
669	  // Here-string: `<<<`. Feeds inline content to stdin — not a write. Next
670	  // token is the inline string.
671	  if (/^(?:\d+|&)?<<<$/u.test(value)) {
672	    return { isWrite: false, consumedExtra: 1 };
673	  }
674	
675	  // Process substitution: `<(` or `>(`. Spans tokens until one ending in `)`.
676	  if (value === "<(" || value === ">(") {
677	    let extra = 0;
678	    for (let j = index + 1; j < tokens.length; j += 1) {
679	      extra += 1;
680	      if (tokens[j]!.value.endsWith(")")) break;
681	    }
682	    return { isWrite: false, consumedExtra: extra };
683	  }
684	
685	  // Read-write `<>file`: mutates the target.
686	  if (/^(?:\d+|&)?<>$/u.test(value)) {
687	    return { isWrite: true, consumedExtra: 1 };
688	  }
689	
690	  // Input redirect `<file`: not a write, but skip the target so it doesn't
691	  // leak into the positional list.
692	  if (/^(?:\d+|&)?<$/u.test(value)) {
693	    return { isWrite: false, consumedExtra: 1 };
694	  }
695	
696	  // Clobber `>|file`: forced write — except `>|/dev/null`, which is still a
697	  // discard (the clobber flag only matters for files that already exist).
698	  if (/^(?:\d+|&)?>\|$/u.test(value)) {
699	    if (nextValue === "/dev/null") return { isWrite: false, consumedExtra: 1 };
700	    return { isWrite: true, consumedExtra: 1 };
701	  }
702	
703	  // FD-copy operator `>&` (next token is a digit fd or, rarely, a file).
704	  if (/^(\d*|&)>>?&$/u.test(value)) {
705	    if (nextValue === undefined) return { isWrite: false, consumedExtra: 0 };
706	    return { isWrite: false, consumedExtra: 1 };
707	  }
708	
709	  // Output redirect operator: `>`, `>>`, `1>`, `2>`, `&>`, `&>>`, ...
710	  const opMatch = /^(\d+|&)?>>?$/u.exec(value);
711	  if (opMatch) {
712	    const prefix = opMatch[1] ?? "";
713	    if (nextValue === undefined) return { isWrite: false, consumedExtra: 0 };
714	
715	    // Stderr / other-fd redirects (`2>file`, `3>file`) are diagnostic, not a
716	    // content write. Skip the target.
717	    if (/^[2-9]/u.test(prefix)) return { isWrite: false, consumedExtra: 1 };
718	
719	    // `/dev/null` is a discard, not a real file.
720	    if (nextValue === "/dev/null") return { isWrite: false, consumedExtra: 1 };
721	
722	    return { isWrite: true, consumedExtra: 1 };
723	  }
724	
725	  return null;
726	}
727	
728	function getCommandTokenIndex(tokens: readonly ShellToken[]): number {
729	  let index = 0;
730	  while (index < tokens.length) {
731	    const token = tokens[index];
732	    // A quoted token like `"FOO=bar"` is a literal word, not an env assignment.
733	    if (token === undefined || token.quoted) break;
734	    if (!ENV_ASSIGNMENT_PATTERN.test(token.value)) break;
735	    index += 1;
736	  }
737	  return index;
738	}
739	
740	function segmentHasWriteShape(argTokens: readonly ShellToken[]): boolean {
741	  let i = 0;
742	  while (i < argTokens.length) {
743	    const redir = scanRedirectAt(argTokens, i);
744	    if (redir) {
745	      if (redir.isWrite) return true;
746	      i += 1 + redir.consumedExtra;
747	      continue;
748	    }
749	    i += 1;
750	  }
751	  return false;
752	}
753	
754	/** Walks argument tokens, skipping flags (and their values, when known) and
755	 * any redirection operator + its consumed targets. Returns the literal values
756	 * of positional arguments (quoted-ness is no longer relevant once they reach
757	 * the dispatched classifier). */
758	function collectPositionals(
759	  argTokens: readonly ShellToken[],
760	  flagsWithValue: ReadonlySet<string>,
761	): string[] {
762	  const positionals: string[] = [];
763	  let i = 0;
764	  while (i < argTokens.length) {
765	    const token = argTokens[i]!;
766	
767	    const redir = scanRedirectAt(argTokens, i);
768	    if (redir) {
769	      i += 1 + redir.consumedExtra;
770	      continue;
771	    }
772	
773	    // Flags only count as flags when unquoted — `"-n"` as quoted arg is a
774	    // literal positional, not a flag.
775	    if (!token.quoted && token.value.startsWith("-") && token.value !== "-") {
776	      if (flagsWithValue.has(token.value)) {
777	        i += 2;
778	        continue;
779	      }
780	      i += 1;
781	      continue;
782	    }
783	
784	    positionals.push(token.value);
785	    i += 1;
786	  }
787	  return positionals;
788	}
