790	function classifyShellSegment(
791	  tokens: readonly ShellToken[],
792	  fullCommand: string,
793	): SegmentClassification {
794	  const commandIndex = getCommandTokenIndex(tokens);
795	  const commandToken = tokens[commandIndex];
796	  if (commandToken === undefined) return { kind: "none" };
797	
798	  const argTokens = tokens.slice(commandIndex + 1);
799	  const commandName = baseExecutableName(commandToken.value);
800	
801	  // Write-shape: specific commands that mutate, regardless of redirects.
802	  if (commandName === "tee") return { kind: "write" };
803	  if (
804	    commandName === "sed" &&
805	    argTokens.some((t) => !t.quoted && isSedInPlaceFlag(t.value))
806	  ) {
807	    return { kind: "write" };
808	  }
809	  // Heredocs and file redirections within this segment.
810	  if (segmentHasWriteShape(argTokens)) return { kind: "write" };
811	
812	  switch (commandName) {
813	    case "rg":
814	    case "grep": {
815	      const positionals = collectPositionals(
816	        argTokens,
817	        SEARCH_FLAGS_WITH_VALUE,
818	      );
819	      return {
820	        kind: "intent",
821	        intent: {
822	          type: "search",
823	          cmd: fullCommand,
824	          query: positionals[0] ?? null,
825	          path:
826	            positionals.length > 1
827	              ? positionals[positionals.length - 1]!
828	              : null,
829	        },
830	      };
831	    }
832	    case "find": {
833	      const positionals = collectPositionals(argTokens, FIND_FLAGS_WITH_VALUE);
834	      const path = positionals[0];
835	      if (!path) return { kind: "none" };
836	      return {
837	        kind: "intent",
838	        intent: { type: "list_files", cmd: fullCommand, path },
839	      };
840	    }
841	    case "ls": {
842	      const positionals = collectPositionals(argTokens, NO_FLAGS_WITH_VALUE);
843	      const path = positionals[0] ?? ".";
844	      return {
845	        kind: "intent",
846	        intent: { type: "list_files", cmd: fullCommand, path },
847	      };
848	    }
849	    case "cat":
850	    case "nl": {
851	      const positionals = collectPositionals(argTokens, NO_FLAGS_WITH_VALUE);
852	      const path = positionals[0];
853	      if (!path) return { kind: "none" };
854	      return {
855	        kind: "intent",
856	        intent: { type: "read", cmd: fullCommand, name: commandName, path },
857	      };
858	    }
859	    case "head":
860	    case "tail": {
861	      const positionals = collectPositionals(
862	        argTokens,
863	        HEAD_TAIL_FLAGS_WITH_VALUE,
864	      );
865	      const path = positionals[0];
866	      if (!path) return { kind: "none" };
867	      return {
868	        kind: "intent",
869	        intent: { type: "read", cmd: fullCommand, name: commandName, path },
870	      };
871	    }
872	    case "sed": {
873	      // Only classify `sed -n SCRIPT FILE` as a read. Other sed invocations are
874	      // too variable to pattern-match reliably.
875	      if (!argTokens.some((t) => !t.quoted && t.value === "-n")) {
876	        return { kind: "none" };
877	      }
878	      const positionals = collectPositionals(argTokens, NO_FLAGS_WITH_VALUE);
879	      const path = positionals[1]; // [script, file]
880	      if (!path) return { kind: "none" };
881	      return {
882	        kind: "intent",
883	        intent: { type: "read", cmd: fullCommand, name: "sed", path },
884	      };
885	    }
886	    default:
887	      return { kind: "none" };
888	  }
889	}
