891	export function hasShellWriteShape(command: string): boolean {
892	  const segments = splitShellCommandSegments(command);
893	  return segments.some(
894	    (segment) => classifyShellSegment(segment, command).kind === "write",
895	  );
896	}
897	
898	export function parseShellCommandIntents(
899	  command: string | undefined,
900	): ViewToolParsedIntent[] {
901	  if (!command) return [];
902	
903	  const segments = splitShellCommandSegments(command);
904	  const classifications = segments.map((segment) =>
905	    classifyShellSegment(segment, command),
906	  );
907	
908	  // Any segment that writes disqualifies the whole command from "exploring".
909	  if (classifications.some((c) => c.kind === "write")) return [];
910	
911	  for (const classification of classifications) {
912	    if (classification.kind === "intent") return [classification.intent];
913	  }
914	  return [];
915	}
