917	export function formatToolCallCommand(
918	  toolName: string,
919	  args: Record<string, unknown> | null,
920	): string {
921	  if (!args) return toolName;
922	
923	  const desc = TOOL_TABLE[toolName];
924	  if (!desc) return formatUnknownToolCommand(toolName, args);
925	
926	  if (desc.formatCommand) {
927	    return desc.formatCommand(toolName, args);
928	  }
929	
930	  const primary = getFirstStringField(args, desc.argKeys) ?? "";
