+    });
+
+    expect(
+      buildErrorDisplay(
+        buildErrorMessage({
+          message: "Provisioning thread failed",
+          detail,
+        }),
+      ),
+    ).toEqual({
+      title: "Provisioning thread failed",
+      detail,
+    });
+  });
+});
