  if (!normalized.includes("\\n") && !normalized.includes("\\r\\n")) {
    return normalized;
  }
  if (/[A-Za-z]:\\\\/.test(normalized)) return normalized;
  return normalized.replaceAll("\\r\\n", "\n").replaceAll("\\n", "\n");
}

function normalizeProvisioningErrorDetail(detail: string): string {
  let normalized = normalizeErrorMessageText(detail).trim();
  if (!normalized) return normalized;
  if (!normalized.startsWith(".bb-env-setup.sh failed:")) {
    return normalized;
  }

  normalized = normalized.replace(
    /^(\.bb-env-setup\.sh failed:)\s*•\s*/i,
    "$1\n• ",
  );
  return normalized.replace(/\s+•\s+/g, "\n• ");
}

function normalizeErrorDetail(
  detail: string,
  normalizer: ErrorDetailNormalizer | undefined,
): string {
  return (normalizer ?? normalizeErrorMessageText)(detail).trim();
}

function resolveErrorDetail({
  copy,
  message,
}: ResolveErrorDetailArgs): string | undefined {
  const title = copy?.title;
  const normalizer = copy?.normalizeDetail;
  const detail = message.detail?.trim();
  if (detail) {
    return normalizeErrorDetail(detail, normalizer);
  }

  if (!copy) {
    return undefined;
  }

  const rawMessage = message.message.trim();
  if (!rawMessage || rawMessage === title) {
    return undefined;
  }
  return normalizeErrorDetail(rawMessage, normalizer);
}

export function buildErrorDisplay(message: ViewErrorMessage): ErrorDisplay {
  const copy = message.code ? KNOWN_ERROR_COPY[message.code] : undefined;
  const fallbackTitle = message.message.trim() || "Error event";
  const title = copy?.title ?? normalizeErrorMessageText(fallbackTitle).trim();
  const detail = resolveErrorDetail({ copy, message });

  return {
    title,
    ...(detail ? { detail } : {}),
    ...(copy?.hint ? { hint: copy.hint } : {}),
  };
}

