  onOpenLocalFileLink,
  projectId,
  resolveUserAttachmentImageSrc,
  row,
  rowContainerClassName,
  rowState,
  rows,
  themeType = DEFAULT_THEME_TYPE,
  turnRowsController,
}: TimelineRowEntryProps) {
  const presentation = useMemo(() => getTimelinePresentationRow(row), [row]);
  const behavior = getRowBehavior(row, rowState);

  return (
    <div data-thread-row-id={row.id} className={rowContainerClassName}>
      {row.kind === "conversation" ? (
        <ConversationTimelineEntry
          row={row}
          projectId={projectId}
          onOpenLocalFileLink={onOpenLocalFileLink}
          resolveUserAttachmentImageSrc={resolveUserAttachmentImageSrc}
        />
      ) : row.kind === "system" ? (
        <SystemEntry presentation={presentation} />
      ) : row.kind === "work" ? (
        <WorkEntry
          initialExpanded={behavior.autoExpand}
          isOngoing={behavior.isOngoing}
          onOpenLocalFileLink={onOpenLocalFileLink}
          presentation={presentation}
          projectId={projectId}
          resolveUserAttachmentImageSrc={resolveUserAttachmentImageSrc}
          row={row}
          rowState={rowState}
          themeType={themeType}
          turnRowsController={turnRowsController}
        />
      ) : row.kind === "group" ? (
        <GroupEntry
          enclosingScopeInProgress={enclosingScopeInProgress}
          initialExpanded={behavior.autoExpand}
          isOngoing={behavior.isOngoing}
          onOpenLocalFileLink={onOpenLocalFileLink}
          presentation={presentation}
          projectId={projectId}
          resolveUserAttachmentImageSrc={resolveUserAttachmentImageSrc}
          row={row}
          rowContainerClassName={rowContainerClassName}
          rows={rows}
          rowState={rowState}
          themeType={themeType}
          turnRowsController={turnRowsController}
        />
      ) : (
        <TurnEntry
          enclosingScopeInProgress={enclosingScopeInProgress}
          initialExpanded={behavior.autoExpand}
          onOpenLocalFileLink={onOpenLocalFileLink}
          presentation={presentation}
          projectId={projectId}
          resolveUserAttachmentImageSrc={resolveUserAttachmentImageSrc}
          row={row}
          rowContainerClassName={rowContainerClassName}
          rows={rows}
          rowState={rowState}
          themeType={themeType}
          turnRowsController={turnRowsController}
        />
      )}
    </div>
  );
}

function NestedTimelineRowsContent({
  enclosingScopeInProgress,
  onOpenLocalFileLink,
  projectId,
  resolveUserAttachmentImageSrc,
  rowContainerClassName,
  rowState,
  rows,
  themeType,
  turnRowsController,
}: NestedTimelineRowsContentProps) {
  return (
    <>
      {rows.map((row) => (
        <MemoizedTimelineRowEntry
          key={row.id}
          enclosingScopeInProgress={enclosingScopeInProgress}
          onOpenLocalFileLink={onOpenLocalFileLink}
